-- Table structure for alert_notifications
-- ----------------------------
DROP TABLE IF EXISTS `alert_notifications`;
CREATE TABLE `alert_notifications`  (
  `alert_id` int NOT NULL AUTO_INCREMENT,
  `alert_key` varchar(120) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `student_id` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `student_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `alert_type` varchar(30) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `alert_level` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `message` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `notify_channels` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '',
  `status` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL DEFAULT '待处理',
  `created_at` datetime NOT NULL,
  `resolved_at` datetime NULL DEFAULT NULL,
  `resolved_by` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '',
  PRIMARY KEY (`alert_id`) USING BTREE,
  UNIQUE INDEX `uniq_alert_key`(`alert_key`) USING BTREE,
  INDEX `idx_alert_status`(`status`) USING BTREE,
  INDEX `idx_alert_student`(`student_id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 28 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = Dynamic;

